import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';

export default function Register() {
  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1 flex items-center justify-center px-6 py-10">
        <div className="w-full max-w-md p-8 rounded-2xl border border-gray-100 shadow-card">
          <h1 className="text-2xl font-bold text-gray-900">Create account</h1>
          <p className="mt-1 text-sm text-gray-600">Join WorkNest to find your next workspace</p>
          <form className="mt-6 space-y-4">
            <input type="text" placeholder="Full name" className="w-full h-11 px-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-400" />
            <input type="email" placeholder="Email" className="w-full h-11 px-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-400" />
            <input type="password" placeholder="Password" className="w-full h-11 px-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-400" />
            <button className="w-full h-11 rounded-lg bg-brand-600 text-white font-semibold hover:bg-brand-700 transition">Create account</button>
          </form>
          <p className="mt-4 text-sm text-gray-600">Have an account? <a href="/login" className="text-brand-700 font-semibold">Sign in</a></p>
        </div>
      </main>
      <Footer />
    </div>
  );
}
